import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"医学衷中参西录","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/07-医学衷中参西录（张锡纯）.md","filePath":"tcm-data/04-明清/07-医学衷中参西录（张锡纯）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/04-明清/07-医学衷中参西录（张锡纯）.md"};function n(s,t,i,d,h,g){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="医学衷中参西录" tabindex="-1">医学衷中参西录 <a class="header-anchor" href="#医学衷中参西录" aria-label="Permalink to &quot;医学衷中参西录&quot;">​</a></h1><blockquote><p>张锡纯（1860-1933年），河北盐山人 中国近代医学第一人，&quot;中西医结合&quot;的先驱 代表作：《医学衷中参西录》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字寿甫</li><li><strong>生平</strong>：自幼习儒，后弃儒从医，一生临床，晚年创办中医学校</li><li><strong>著作</strong>：《医学衷中参西录》（30卷，150万字）</li><li><strong>学术地位</strong>：&quot;中医近代第一人&quot;，<strong>&quot;衷中参西&quot;</strong>（以中医为本，参酌西医）</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-衷中参西" tabindex="-1">1. 衷中参西 <a class="header-anchor" href="#_1-衷中参西" aria-label="Permalink to &quot;1. 衷中参西&quot;">​</a></h3><blockquote><p><strong>「中医之理，原多包括西医之理，通天彻地。以中医为本，取西医之长以辅之。」</strong></p></blockquote><ul><li>不排斥西医，但坚持中医理论的独立性</li><li>善用西医生理解剖知识阐释中医</li><li>如用&quot;胃之降浊&quot;解释西医的消化吸收</li></ul><h3 id="_2-大气论" tabindex="-1">2. 大气论 <a class="header-anchor" href="#_2-大气论" aria-label="Permalink to &quot;2. 大气论&quot;">​</a></h3><blockquote><p><strong>「人身之大气，原名为宗气。内而脏腑，外而经络，皆此气之贯通。」</strong></p></blockquote><ul><li>张锡纯特别重视<strong>宗气</strong>（胸中大气）</li><li>大气下陷 → 气短、脉沉、乏力</li><li><strong>升陷汤</strong>为张锡纯的独创方</li></ul><h3 id="_3-脏腑升降" tabindex="-1">3. 脏腑升降 <a class="header-anchor" href="#_3-脏腑升降" aria-label="Permalink to &quot;3. 脏腑升降&quot;">​</a></h3><blockquote><p><strong>「脾升胃降，乃人身气化之总枢。」</strong></p></blockquote><p>继承了《内经》和黄元御的升降理论。</p><h3 id="_4-重用生石膏" tabindex="-1">4. 重用生石膏 <a class="header-anchor" href="#_4-重用生石膏" aria-label="Permalink to &quot;4. 重用生石膏&quot;">​</a></h3><blockquote><p><strong>「石膏之性，又最凉而能散，有透表解肌之力。」</strong></p></blockquote><p>张锡纯是<strong>重用石膏</strong>的代表人物，认为石膏&quot;凉而不寒，散而不伤&quot;。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>升陷汤</strong></td><td style="text-align:left;">黄芪、知母、柴胡、桔梗、升麻</td><td style="text-align:left;">大气下陷</td></tr><tr><td style="text-align:left;"><strong>镇肝熄风汤</strong></td><td style="text-align:left;">牛膝、代赭石、龙骨、牡蛎、龟板、白芍、玄参、天冬、川楝子、麦芽、茵陈、甘草</td><td style="text-align:left;">肝阳上亢（高血压）</td></tr><tr><td style="text-align:left;"><strong>活络效灵丹</strong></td><td style="text-align:left;">当归、丹参、乳香、没药</td><td style="text-align:left;">各种瘀血痛</td></tr><tr><td style="text-align:left;"><strong>玉液汤</strong></td><td style="text-align:left;">黄芪、山药、知母、葛根、五味子、天花粉、鸡内金</td><td style="text-align:left;">消渴（糖尿病）</td></tr><tr><td style="text-align:left;"><strong>资生汤</strong></td><td style="text-align:left;">山药、玄参、白术、生鸡内金、牛蒡</td><td style="text-align:left;">虚劳（肺结核）</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「中医之理，原多包括西医之理。」</strong></p></blockquote><blockquote><p><strong>「用药如用兵，贵在灵活运用，不可拘泥。」</strong></p></blockquote><blockquote><p><strong>「凡人病有气血，而医者能辨明其虚实，则治之不难。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>影响了<strong>李可</strong>的用药风格（大剂量用药）</li><li><strong>镇肝熄风汤</strong>至今是高血压的常用方</li><li><strong>衷中参西</strong>的思路在当代被广泛接受</li><li>其大量临床医案仍然是中医学习的宝库</li></ul><hr><p><em>本条目为精简框架版。张锡纯的医案可独立扩展为《衷中参西录医案选》。</em></p>',32)])])}const q=e(r,[["render",n]]);export{c as __pageData,q as default};
